        D("P30", "Smelting Plant", CardType.Prelude, 0, [Tag.Building], Expansion.Prelude, [], null, "Raise oxygen 2 steps. Gain 5 steel."),
        D("P31", "Society Support", CardType.Prelude, 0, [], Expansion.Prelude, [], null, "Increase your plant, energy and heat production 1 step. Decrease money production 1 step."),
        D("P32", "Supplier", CardType.Prelude, 0, [Tag.Power], Expansion.Prelude, [], null, "Increase your energy production 2 steps. Gain 4 steel."),
        D("P33", "Supply Drop", CardType.Prelude, 0, [], Expansion.Prelude, [], null, "Gain 3 titanium, 8 steel and 3 plants."),
        D("P34", "UNMI Contractor", CardType.Prelude, 0, [Tag.Earth], Expansion.Prelude, [], null, "Increase your TR 3 steps. Draw a card."),
