        };

        return cards.ToImmutableDictionary(c => c.Id);
    }

    private static CardDefinition D(
        string id, string name, CardType type, int cost,
        ImmutableArray<Tag> tags, Expansion expansion,
        ImmutableArray<CardRequirement> requirements,
        VictoryPoints? victoryPoints, string description) => new()
    {
        Id = id,
        Name = name,
        Type = type,
        Cost = cost,
        Tags = tags,
        Expansion = expansion,
        Requirements = requirements,
        VictoryPoints = victoryPoints,
        Description = description,
    };
}
